from flask import Flask, redirect, url_for, session, request
from flask_session import Session
import requests
import json
import jwt
from urllib.parse import urlencode

app = Flask(__name__)
app.config["SESSION_PERMANENT"] = False
app.config["SESSION_TYPE"] = "filesystem"
Session(app)

# Client ID and secret from OpenID Connect provider
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'

# Provider's authorization URL
AUTHORIZATION_URL = 'https://your_provider_authorize_url.com/authorize'

# Provider's token endpoint
TOKEN_ENDPOINT = 'https://your_provider_token_endpoint.com/token'

# Provider's user info endpoint
USER_INFO_ENDPOINT = 'https://your_provider_user_info_endpoint.com/userinfo'

@app.route('/')
def index():
    return redirect(url_for('login'))

@app.route('/login')
def login():
    # Generate a random state for nonce validation
    state = jwt.encode({'nonce': str(request.sid)}, CLIENT_SECRET, algorithm='HS256').decode('utf-8')

    # Redirect to provider's authorization URL with client ID and state
    params = {
        'client_id': CLIENT_ID,
        'redirect_uri': url_for('callback', _external=True),
        'response_type': 'code',
        'scope': 'openid profile email',
        'state': state
    }
    return redirect(f'{AUTHORIZATION_URL}?{urlencode(params)}')

@app.route('/callback')
def callback():
    # Get authorization code from query string
    code = request.args.get('code')

    # Exchange code for tokens using client secret and client ID
    headers = {
        'Content-Type': 'application/x-www-form-urlencoded'
    }
    data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': url_for('callback', _external=True),
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    }
    response = requests.post(TOKEN_ENDPOINT, headers=headers, data=data)
    tokens = json.loads(response.text)

    # Decode id token to get user claims
    headers = {
        'Authorization': f'Bearer {tokens["id_token"]}'
    }
    response = requests.get(USER_INFO_ENDPOINT, headers=headers)
    user_info = json.loads(response.text)

    # Store user information in session
    session['user'] = {
        'name': user_info['name'],
        'email': user_info['email']
    }

    return redirect(url_for('protected'))

@app.route('/protected')
def protected():
    if 'user' in session:
        return f'Hello, {session["user"]["name"]}!'
    else:
        return redirect(url_for('login'))

if __name__ == '__main__':
    app.run(debug=True)